import "fmt"

// Tier represents an analysis capability tier for a programming language.
type Tier int

const (
	TierNone    Tier = iota // No analysis support
	TierGeneric             // File-level generic analysis only
	TierLint                // Lint support
	TierParse               // AST-level parse support
	TierFull                // Full semantic analysis
)

// tierStrings maps Tier values to human-readable names.
var tierStrings = map[Tier]string{
	TierNone:    "None",
	TierGeneric: "Generic",
	TierLint:    "Lint",
	TierParse:   "Parse",
	TierFull:    "Full",
}

// String returns the human-readable name of the tier, or a fallback
// for unrecognized values.
func (t Tier) String() string {
	if s, ok := tierStrings[t]; ok {
		return s
	}
	return fmt.Sprintf("Tier(%d)", t)
}

// languageTiers maps every known language ID to its analysis capability tier.
var languageTiers = map[string]Tier{
	"go":      TierFull,
	"ts":      TierFull,
	"js":      TierFull,
	"py":      TierFull,
	"rs":      TierFull,
	"rb":      TierGeneric,
	"java":    TierGeneric,
	"kt":      TierGeneric,
	"sh":      TierGeneric,
	"c":       TierGeneric,
	"cpp":     TierGeneric,
	"cs":      TierGeneric,
	"swift":   TierGeneric,
	"php":     TierGeneric,
	"elixir":  TierGeneric,
	"erlang":  TierGeneric,
	"scala":   TierGeneric,
	"lua":     TierGeneric,
	"r":       TierGeneric,
	"zig":     TierGeneric,
	"sql":     TierGeneric,
	"proto":   TierGeneric,
}

// TierForLanguage returns the analysis capability tier for the given language ID.
// Unknown languages return TierGeneric.
func TierForLanguage(lang string) Tier {
	if t, ok := languageTiers[lang]; ok {
		return t
	}
	return TierGeneric
}

