func TestLanguageTiersRegistry(t *testing.T) {
	// Every expected language must be present with the correct tier.
	for lang, wantTier := range expectedLanguageTiers {
		gotTier, ok := languageTiers[lang]
		if !ok {
			t.Errorf("language %q missing from languageTiers registry", lang)
			continue
		}
		if gotTier != wantTier {
			t.Errorf("language %q: got tier %s, want %s", lang, gotTier, wantTier)
		}
	}

	// No extra entries in the registry beyond what's expected.
	if len(languageTiers) != len(expectedLanguageTiers) {
		for lang := range languageTiers {
			if _, ok := expectedLanguageTiers[lang]; !ok {
				t.Errorf("unexpected language %q in registry (not in expectedLanguageTiers)", lang)
			}
		}
	}
}

